#!/usr/bin/env node
/**
 * Create GitHub releases for tarballs generated by the nightly CD GitHub
 * workflow.
 *
 * `.github/workflows/cd-github-releases.yml` invokes this script after
 * `npm run publish-ci` has bumped versions, created beachball tags, and packed
 * tarballs into `publish_artifacts/`. Each tarball gets a matching GitHub
 * release and is uploaded as an asset for the nightly Azure npm publishing
 * pipeline.
 */

import { basename } from "node:path";
import {
    createRelease,
    getReleaseByTag,
    listTarballs,
    makeReleaseTag,
    PUBLISH_ARTIFACTS_DIR,
    readTarballPackageJson,
    resolveRepository,
    resolveToken,
    uploadReleaseAsset,
} from "./release-utils.mjs";

/**
 * @param {{ pkgName: string, version: string, tag: string }} options
 * @returns {string}
 */
function makeReleaseBody({ pkgName, version, tag }) {
    return [
        `## ${pkgName}@${version}`,
        "",
        `- Package: \`${pkgName}\``,
        `- Version: \`${version}\``,
        `- Tag: \`${tag}\``,
        "",
        "The attached tarball will be published to npm by the nightly Azure release pipeline.",
    ].join("\n");
}

/**
 * @param {unknown} error
 * @returns {string}
 */
function formatError(error) {
    if (error instanceof Error) {
        return error.stack || error.message;
    }
    return String(error);
}

/**
 * @param {{ token: string, owner: string, repo: string, tarballPath: string }} options
 * @returns {Promise<void>}
 */
async function processTarball({ token, owner, repo, tarballPath }) {
    const { name: pkgName, version } = readTarballPackageJson(tarballPath);
    const tag = makeReleaseTag(pkgName, version);
    const fileName = basename(tarballPath);

    const existingRelease = await getReleaseByTag({ token, owner, repo, tag });
    if (existingRelease) {
        console.log(`Skipping ${pkgName}@${version} — release already exists`);
        return;
    }

    const release = await createRelease({
        token,
        owner,
        repo,
        tag,
        name: `${pkgName}@${version}`,
        body: makeReleaseBody({ pkgName, version, tag }),
    });

    await uploadReleaseAsset({
        token,
        uploadUrl: release.upload_url,
        filePath: tarballPath,
        fileName,
    });

    console.log(
        `Created release ${tag} for ${pkgName}@${version} and uploaded ${fileName}`,
    );
}

async function main() {
    const { owner, repo } = resolveRepository();
    const token = resolveToken();
    const tarballs = await listTarballs();

    if (tarballs.length === 0) {
        console.log(`No tarballs found in ${PUBLISH_ARTIFACTS_DIR}; nothing to release.`);
        return;
    }

    let hasErrors = false;

    for (const tarballPath of tarballs) {
        try {
            await processTarball({ token, owner, repo, tarballPath });
        } catch (error) {
            hasErrors = true;
            console.error(`Failed to process ${basename(tarballPath)}:`);
            console.error(formatError(error));
        }
    }

    if (hasErrors) {
        process.exitCode = 1;
    }
}

await main();
